$ErrorActionPreference='Stop';. (Join-Path $PSScriptRoot 'maple-synthetic-docker-topology-plan.ps1')
function A($v,$m){if(-not$v){throw $m}}
$id=[guid]'11111111-2222-4333-8444-555555555555';$plan=New-MapleSyntheticDockerTopologyPlan $id 62131 62132;A(Assert-MapleSyntheticDockerTopologyPlan $plan)'plan refused';A($plan.Kind-ceq'planning-topology-sketch'-and-not$plan.Executable)'not honest topology plan';A(-not$plan.PortPreflight.Implemented-and$plan.PortPreflight.KnownRace-match'cannot reserve')'port race not explicit';A(-not$plan.FixtureLineage.Resolved-and$plan.FixtureLineage.Reason-match'create commands are intentionally omitted')'fixture lineage overclaimed';A(($plan.LoopbackPublishes-join'|')-ceq'127.0.0.1:62131:5432|127.0.0.1:62132:3000')'publish topology not loopback'
foreach($resource in $plan.Resources){$index=[array]::IndexOf([object[]]$plan.Cleanup,($plan.Cleanup|Where-Object{$_.Action-eq'inspect'-and$_.Name-ceq$resource.Name}|Select-Object -First 1));A($index-ge0)'ownership inspect missing';$later=@($plan.Cleanup|Select-Object -Skip($index+1)|Where-Object{$_.Name-ceq$resource.Name});A($later.Count-ge1-and@($later|Where-Object{-not$_.OnlyAfterExactInspection}).Count-eq0)'cleanup not ownership gated'}
$source=Get-Content -Raw (Join-Path $PSScriptRoot 'maple-synthetic-docker-topology-plan.ps1');A($source-match'non-executing planning/topology sketch'-and-not($source-match'ProcessStartInfo|Invoke-MapleSwapStateMachine'))'execution claim remains';$planJson=$plan|ConvertTo-Json -Depth 9;A(-not($planJson-match'POSTGRES_PASSWORD|JWT_SECRET')-and-not($source-match'postgres:[^@''"]|alpine:[^@''"]'))'credential or mutable fixture image present'
Write-Output 'MAPLE_SYNTHETIC_DOCKER_TOPOLOGY_PLAN_REGRESSION_PASS'
